147	long long compute_component_sum_sq(Bits100 mask) {
148	    long long total = 0;
149	    while (!mask.is_zero()) {
150	        int seed = mask.ctz();
151	        Bits100 comp;
152	        comp.set_bit(seed);
153	
154	        Bits100 prev;
155	        do {
156	            prev = comp;
157	            comp = comp | (dilate(comp) & mask);
158	        } while (comp != prev);
159	
160	        int size = comp.popcount();
161	        total += (long long)size * size;
162	        mask = mask & (~comp);
163	    }
164	    return total;
