461	    int sample_count_this_depth = config.samples[sample_count_param_idx];
462	    int actual_num_samples = std::min(sample_count_this_depth, num_empty);
463	
464	    if (actual_num_samples == 0) {
465	        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
466	        return state_after_tilt.evaluate();
467	    }
