473	            p_val = s + 1;
474	        } else {
475	            p_val = rng.uniform_int(1, num_empty);
476	        }
477	
478	        GameState S_after_placement = state_after_tilt;
479	        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val);
480	        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
481	        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;
482	
483	        double max_eval = std::numeric_limits<double>::lowest();
484	        for (int dir_idx = 0; dir_idx < NUM_DIRECTIONS; ++dir_idx) {
485	            GameState S_after_tilt = S_after_placement;
486	            S_after_tilt.apply_tilt(dir_idx);
487	            double val = eval_lookahead(S_after_tilt, S_after_placement.turn_num_1_indexed, depth_remaining - 1, config);
