struct Bits100 {
    uint64_t lo;
    uint64_t hi;

    Bits100() : lo(0), hi(0) {}
    Bits100(uint64_t l, uint64_t h) : lo(l), hi(h) {}

    void set_bit(int pos) {
        if (pos < 64) lo |= (1ULL << pos);
        else hi |= (1ULL << (pos - 64));
    }

    void clear_bit(int pos) {
        if (pos < 64) lo &= ~(1ULL << pos);
        else hi &= ~(1ULL << (pos - 64));
    }

    bool get_bit(int pos) const {
        if (pos < 64) return (lo >> pos) & 1;
        return (hi >> (pos - 64)) & 1;
    }

    int popcount() const {
        return __builtin_popcountll(lo) + __builtin_popcountll(hi);
    }

    bool is_zero() const { return lo == 0 && hi == 0; }

    int ctz() const {
        if (lo) return __builtin_ctzll(lo);
        if (hi) return 64 + __builtin_ctzll(hi);
        return 100;
    }

    Bits100 operator&(const Bits100& o) const { return {lo & o.lo, hi & o.hi}; }
    Bits100 operator|(const Bits100& o) const { return {lo | o.lo, hi | o.hi}; }
    Bits100 operator~() const { return {~lo, (~hi) & 0xFFFFFFFFFULL}; }
    bool operator==(const Bits100& o) const { return lo == o.lo && hi == o.hi; }
    bool operator!=(const Bits100& o) const { return lo != o.lo || hi != o.hi; }

    Bits100 clear_lowest_bit() const {
        if (lo) return {lo & (lo - 1), hi};
        return {lo, hi & (hi - 1)};
    }
};

Bits100 NOT_COL9;
Bits100 NOT_COL0;

void init_masks() {
    NOT_COL9.lo = 0; NOT_COL9.hi = 0;
    NOT_COL0.lo = 0; NOT_COL0.hi = 0;
    for (int r = 0; r < 10; r++) {
        for (int c = 0; c < 10; c++) {
            int pos = r * 10 + c;
            if (c != 9) NOT_COL9.set_bit(pos);
            if (c != 0) NOT_COL0.set_bit(pos);
        }
    }
}

inline Bits100 shl1(Bits100 m) {
    Bits100 r;
    r.lo = m.lo << 1;
    r.hi = ((m.hi << 1) | (m.lo >> 63)) & 0xFFFFFFFFFULL;
    return r;
}

inline Bits100 shr1(Bits100 m) {
    return {(m.lo >> 1) | (m.hi << 63), m.hi >> 1};
}

inline Bits100 shl10(Bits100 m) {
    Bits100 r;
    r.lo = (m.lo << 10);
    r.hi = ((m.hi << 10) | (m.lo >> 54)) & 0xFFFFFFFFFULL;
    return r;
}

inline Bits100 shr10(Bits100 m) {
    return {(m.lo >> 10) | (m.hi << 54), m.hi >> 10};
}

inline Bits100 dilate(Bits100 m) {
    Bits100 right = shl1(m & NOT_COL9);
    Bits100 left = shr1(m & NOT_COL0);
    Bits100 down = shl10(m);
    Bits100 up = shr10(m);
    return right | left | down | up;
}

long long compute_component_sum_sq(Bits100 mask) {
    long long total = 0;
    while (!mask.is_zero()) {
        int seed = mask.ctz();
        Bits100 comp;
        comp.set_bit(seed);

        Bits100 prev;
        do {
            prev = comp;
            comp = comp | (dilate(comp) & mask);
        } while (comp != prev);

        int size = comp.popcount();
        total += (long long)size * size;
        mask = mask & (~comp);
    }
    return total;
}

struct GameState {
    std::array<std::array<int, GRID_SIZE>, GRID_SIZE> board;
    Bits100 masks[4];
    int num_candies;
    int turn_num_1_indexed;

    GameState() : num_candies(0), turn_num_1_indexed(0) {
        for (int i = 0; i < GRID_SIZE; ++i) board[i].fill(0);
        for (int i = 0; i < 4; i++) masks[i] = Bits100();
    }

    void place_candy(int r, int c, int flavor) {
        board[r][c] = flavor;
        masks[flavor].set_bit(r * 10 + c);
        num_candies++;
    }

    std::pair<int, int> find_pth_empty_cell(int p_1_indexed) const {
        int count = 0;
        for (int r_idx = 0; r_idx < GRID_SIZE; ++r_idx) {
            for (int c_idx = 0; c_idx < GRID_SIZE; ++c_idx) {
                if (board[r_idx][c_idx] == 0) {
                    count++;
                    if (count == p_1_indexed) {
                        return {r_idx, c_idx};
                    }
                }
            }
        }
        return {-1, -1};
    }

    int count_empty_cells() const {
        return GRID_SIZE * GRID_SIZE - num_candies;
    }

    void apply_tilt(int dir_idx) {
        masks[1] = Bits100();
        masks[2] = Bits100();
        masks[3] = Bits100();

        if (dir_idx == 0) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = 0;
                for (int r = 0; r < GRID_SIZE; ++r) {
                    if (board[r][c] != 0) {
                        int f = board[r][c];
                        if (r != write_r) {
                            board[write_r][c] = f;
                            board[r][c] = 0;
                        }
                        masks[f].set_bit(write_r * 10 + c);
                        write_r++;
                    }
                }
            }
        } else if (dir_idx == 1) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r) {
                    if (board[r][c] != 0) {
                        int f = board[r][c];
                        if (r != write_r) {
                            board[write_r][c] = f;
                            board[r][c] = 0;
                        }
                        masks[f].set_bit(write_r * 10 + c);
                        write_r--;
                    }
                }
            }
        } else if (dir_idx == 2) {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = 0;
                for (int c = 0; c < GRID_SIZE; ++c) {
                    if (board[r][c] != 0) {
                        int f = board[r][c];
                        if (c != write_c) {
                            board[r][write_c] = f;
                            board[r][c] = 0;
                        }
                        masks[f].set_bit(r * 10 + write_c);
                        write_c++;
                    }
                }
            }
        } else {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    if (board[r][c] != 0) {
                        int f = board[r][c];
                        if (c != write_c) {
                            board[r][write_c] = f;
                            board[r][c] = 0;
                        }
                        masks[f].set_bit(r * 10 + write_c);
                        write_c--;
                    }
                }
            }
        }
    }

    double evaluate_fast() const {
        if (num_candies == 0) return 0.0;

        Bits100 occupied = masks[1] | masks[2] | masks[3];

        int total_h = (shl1(occupied & NOT_COL9) & occupied).popcount();
        int same_h = 0;
        for (int f = 1; f <= 3; f++)
            same_h += (shl1(masks[f] & NOT_COL9) & masks[f]).popcount();

        int total_v = (shl10(occupied) & occupied).popcount();
        int same_v = 0;
        for (int f = 1; f <= 3; f++)
            same_v += (shl10(masks[f]) & masks[f]).popcount();

        int same_adj = same_h + same_v;
        int diff_adj = (total_h - same_h) + (total_v - same_v);

        double compactness = 0.0;
        std::array<int, 4> counts{}, sum_r{}, sum_c{};

        for (int f = 1; f <= 3; f++) {
            Bits100 m = masks[f];
            while (!m.is_zero()) {
                int pos = m.ctz();
                m = m.clear_lowest_bit();
                counts[f]++;
                sum_r[f] += pos / 10;
                sum_c[f] += pos % 10;
            }
        }

        for (int f = 1; f <= 3; f++) {
            if (counts[f] <= 1) continue;
            double com_r = (double)sum_r[f] / counts[f];
            double com_c = (double)sum_c[f] / counts[f];
            Bits100 m = masks[f];
            while (!m.is_zero()) {
                int pos = m.ctz();
                m = m.clear_lowest_bit();
                compactness += std::abs(pos / 10 - com_r) + std::abs(pos % 10 - com_c);
            }
        }

        double t = static_cast<double>(turn_num_1_indexed);
        return (80.0 + 3.0 * t) * same_adj
             - (10.0 + 0.5 * t) * diff_adj
             - std::max(0.0, 180.0 - 1.8 * t) * compactness;
    }

    double evaluate() const {
        if (num_candies == 0) return 0.0;

        long long total_sq_sum = 0;
        for (int f = 1; f <= 3; f++)
            total_sq_sum += compute_component_sum_sq(masks[f]);

        Bits100 occupied = masks[1] | masks[2] | masks[3];

        int total_h = (shl1(occupied & NOT_COL9) & occupied).popcount();
        int same_h = 0;
        for (int f = 1; f <= 3; f++)
            same_h += (shl1(masks[f] & NOT_COL9) & masks[f]).popcount();

        int total_v = (shl10(occupied) & occupied).popcount();
        int same_v = 0;
        for (int f = 1; f <= 3; f++)
            same_v += (shl10(masks[f]) & masks[f]).popcount();

        int same_adj = same_h + same_v;
        int diff_adj = (total_h - same_h) + (total_v - same_v);

        std::array<int, 4> counts{}, sum_r{}, sum_c{};
        for (int f = 1; f <= 3; f++) {
            Bits100 m = masks[f];
            while (!m.is_zero()) {
                int pos = m.ctz();
                m = m.clear_lowest_bit();
                counts[f]++;
                sum_r[f] += pos / 10;
                sum_c[f] += pos % 10;
            }
        }

        double compactness = 0.0;
        double com_r[4] = {}, com_c[4] = {};
        for (int f = 1; f <= 3; f++) {
            if (counts[f] <= 1) continue;
            com_r[f] = (double)sum_r[f] / counts[f];
            com_c[f] = (double)sum_c[f] / counts[f];
            Bits100 m = masks[f];
            while (!m.is_zero()) {
                int pos = m.ctz();
                m = m.clear_lowest_bit();
                compactness += std::abs(pos / 10 - com_r[f]) + std::abs(pos % 10 - com_c[f]);
            }
        }

        double separation = 0.0;
        for (int f1 = 1; f1 <= NUM_FLAVORS; ++f1) {
            if (counts[f1] == 0) continue;
            for (int f2 = f1 + 1; f2 <= NUM_FLAVORS; ++f2) {
                if (counts[f2] == 0) continue;
                separation += std::abs(com_r[f1] - com_r[f2]) + std::abs(com_c[f1] - com_c[f2]);
            }
        }

        double t = static_cast<double>(turn_num_1_indexed);
        double conn_weight = 15.0 + 1.5 * t;
        double adj_weight = 80.0 + 3.0 * t;
        double diff_adj_weight = -(10.0 + 0.5 * t);
        double compactness_weight = -std::max(0.0, 180.0 - 1.8 * t);
        double separation_weight = std::max(0.0, 40.0 - 0.3 * t);

        return conn_weight * total_sq_sum
             + adj_weight * same_adj
             + diff_adj_weight * diff_adj
             + compactness_weight * compactness
             + separation_weight * separation;
    }
};

struct LookaheadConfig {
    int max_depth;
    int samples[3];
    bool use_fast_at_leaf;
};

double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed, int depth_remaining, const LookaheadConfig& config);

double G_time_budget = 1.9;
double G_time_per_turn_budget;
int G_current_turn;

char decide_tilt_direction_logic(const GameState& current_gs_after_placement) {
    double best_overall_eval = std::numeric_limits<double>::lowest();
    int best_dir_idx = 0;

    int turn_T = current_gs_after_placement.turn_num_1_indexed;
    G_current_turn = turn_T;

    double time_now = elapsed_seconds();
    double time_remaining = G_time_budget - time_now;
    int turns_remaining = NUM_TURNS - turn_T + 1;
    G_time_per_turn_budget = time_remaining / turns_remaining;

    LookaheadConfig config;
    if (turn_T <= 12) {
        config.max_depth = 3;
        config.samples[0] = 16;
        config.samples[1] = 7;
        config.samples[2] = 3;
        config.use_fast_at_leaf = true;
    } else {
        config.max_depth = 2;
        config.samples[0] = 40;
        config.samples[1] = 9;
        config.samples[2] = 0;
        config.use_fast_at_leaf = false;
    }

    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        GameState gs_after_tilt = current_gs_after_placement;
        gs_after_tilt.apply_tilt(i);

        double eval = eval_lookahead(gs_after_tilt, turn_T, config.max_depth, config);

        if (eval > best_overall_eval) {
            best_overall_eval = eval;
            best_dir_idx = i;
        }
    }
    return DIR_CHARS[best_dir_idx];
}


double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed, int depth_remaining, const LookaheadConfig& config) {
    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
        return state_after_tilt.evaluate();
    }

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) {
        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
        return state_after_tilt.evaluate();
    }

    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
    int sample_count_param_idx = config.max_depth - depth_remaining;
    int sample_count_this_depth = config.samples[sample_count_param_idx];
    int actual_num_samples = std::min(sample_count_this_depth, num_empty);

    if (actual_num_samples == 0) {
        if (config.use_fast_at_leaf) return state_after_tilt.evaluate_fast();
        return state_after_tilt.evaluate();
    }

    double sum_over_sampled_placements = 0.0;
    for (int s = 0; s < actual_num_samples; ++s) {
        int p_val;
        if (actual_num_samples == num_empty) {
            p_val = s + 1;
        } else {
            p_val = rng.uniform_int(1, num_empty);
        }

        GameState S_after_placement = state_after_tilt;
        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val);
        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;

        double max_eval = std::numeric_limits<double>::lowest();
        for (int dir_idx = 0; dir_idx < NUM_DIRECTIONS; ++dir_idx) {
            GameState S_after_tilt = S_after_placement;
            S_after_tilt.apply_tilt(dir_idx);
            double val = eval_lookahead(S_after_tilt, S_after_placement.turn_num_1_indexed, depth_remaining - 1, config);
            if (val > max_eval) {
                max_eval = val;
            }
        }
        sum_over_sampled_placements += max_eval;
    }

    return sum_over_sampled_placements / actual_num_samples;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    G_start_time = std::chrono::steady_clock::now();
    init_masks();
    rng.seed_from_clock();

    G_flavor_total_counts.fill(0);
    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
        G_flavor_total_counts[G_FLAVOR_SEQUENCE[t]]++;
    }

    GameState current_gs;
    for (int t = 0; t < NUM_TURNS; ++t) {
        current_gs.turn_num_1_indexed = t + 1;

        int p_val;
        std::cin >> p_val;

        std::pair<int, int> candy_loc = current_gs.find_pth_empty_cell(p_val);
        current_gs.place_candy(candy_loc.first, candy_loc.second, G_FLAVOR_SEQUENCE[t]);

        char chosen_dir = decide_tilt_direction_logic(current_gs);

        std::cout << chosen_dir << std::endl;

        int dir_idx = 0;
        for (int k = 0; k < NUM_DIRECTIONS; ++k) {
            if (DIR_CHARS[k] == chosen_dir) {
                dir_idx = k;
                break;
            }
        }
        current_gs.apply_tilt(dir_idx);
    }

